mapper.select:
SELECT  FROM market_sector_watch
market_code = #{marketCode}
ORDER BY enabled DESC, updated_at DESC, id DESC

mapper.update:
UPDATE market_sector_watch
SET collection_state = #{state}, next_retry_at = #{nextRetryAt},
    consecutive_failures = consecutive_failures + 1,
    last_error_code = #{errorCode}, last_error = #{lastError}
WHERE id = #{id} AND run_claim_token = #{token}
